43. /// </summary>
44. // Sealed: JIT can devirtualize and inline interface calls when the concrete type is known.
45. public sealed class DefaultFormatter : IFormatter
46. {
47.     /// <inheritdoc />
48.     public string DateHumanize_Now() => "now";
49. 
50.     /// <inheritdoc />
51.     public string DateHumanize_Never() => "never";
52. 
53.     /// <inheritdoc />
54.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
55.     {
56.         // Avoid Enum.ToString() — it uses reflection and allocates on every call.
57.         var (singular, plural) = GetUnitNames(timeUnit);
58.         var unit = count == 1 ? singular : plural;
59. 
60.         return toWords ? $"{NumberToWords(count)} {unit}" : $"{count} {unit}";
61.     }
62. 
63.     private static (string Singular, string Plural) GetUnitNames(TimeUnit timeUnit) =>
64.         timeUnit switch
65.         {
66.             TimeUnit.Year => ("year", "years"),
67.             TimeUnit.Month => ("month", "months"),
68.             TimeUnit.Day => ("day", "days"),
69.             TimeUnit.Hour => ("hour", "hours"),
70.             TimeUnit.Minute => ("minute", "minutes"),
71.             TimeUnit.Second => ("second", "seconds"),
72.             _ => (timeUnit.ToString().ToLowerInvariant(), timeUnit.ToString().ToLowerInvariant() + "s")
73.         };
74. 
75.     private static string NumberToWords(int number) =>
76.         number switch
77.         {
78.             1 => "one",
79.             2 => "two",
80.             3 => "three",
81.             _ => number.ToString()
82.         };
83. }
