296.     /// Humanizes a DateTime difference relative to a base date.
297.     /// </summary>
298.     /// <param name="input">The date to humanize.</param>
299.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
300.     /// <returns>A human-readable string representing the time difference.</returns>
301.     public string Humanize(DateTime input, DateTime comparedTo)
302.     {
303.         var difference = comparedTo - input;
304.         if (Math.Abs(difference.TotalSeconds) < 2)
