311. 
312.         var result = absDiff.TotalDays switch
313.         {
314.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
315.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
316.             >= 1 => $"{(int)absDiff.TotalDays} days",
317.             _ => absDiff.TotalHours switch
318.             {
319.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
320.                 _ => absDiff.TotalMinutes switch
